const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');
const app = express();
app.use(express.json());
app.get('/health', (_req, res) => res.json({ ok: true }));
app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);
module.exports = app;

// src/server.js
const app = require('./app');

module.exports = app;

// src/modules/projects/routes.js
const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    if (!project) {
      return sendError(res, 404, 'NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const { name } = req.body;
    if (!name || typeof name !== 'string' || name.trim() === '') {
      return sendError(res, 400, 'INVALID_INPUT', 'Name is required and must be a non-empty string');
    }
    const __existingProject = await projectsService.getProjectByName(name);
  if (__existingProject) return sendError(res, 409, 'PROJECT_DUPLICATE', 'Project already exists');
  const project = await projectsService.createProject(name);
  if (!project) return sendError(res, 409, 'PROJECT_DUPLICATE', 'Project already exists');
    res.status(201).json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');

let projectsStore = [];

const getAllProjects = () => {
  return Promise.resolve(projectsStore);
};

const getProjectById = (projectId) => {
  return Promise.resolve(projectsStore.find(p => p.id === projectId));
};

const createProject = (name) => {
  const project = { id: randomUUID(), name };
  projectsStore.push(project);
  return Promise.resolve(project);
};

module.exports = { getAllProjects, getProjectById, createProject };
const __botEvalProjectsDupGuard = module.exports.createProject;
module.exports.createProject = async function createProject(name) {
  const normalized = String(name || '').trim();
  let existing = null;
  if (typeof module.exports.getProjectByName === 'function') {
    existing = await module.exports.getProjectByName(normalized);
  } else if (Array.isArray(projectsStore)) {
    existing = projectsStore.find(project => project && String(project.name || '') === normalized);

  }
  if (existing) return null;
  if (typeof __botEvalProjectsDupGuard === 'function') return __botEvalProjectsDupGuard(normalized);
  return null;
};

const router = require('express').Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');
router.get('/', async (req, res) => {
  const status = typeof req.query?.status === 'string' ? req.query.status : undefined;
  const tasks = await tasksService.getAllTasks(req.params.projectId, status);
  return res.json({ tasks });
});
router.post('/', async (req, res) => {
  const title = String(req.body?.title || "").trim();
  if (!title) return sendError(res, 400, 'BAD_REQUEST', 'Task title is required');
  const task = await tasksService.createTask(req.params.projectId, title);
  return res.status(201).json({ task });
});
router.patch('/:taskId', async (req, res) => {
  const status = String(req.body?.status || '').trim();
  if (status !== 'todo' && status !== 'done') return sendError(res, 400, 'INVALID_STATUS', 'Status must be todo or done');
  const task = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!task) return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  return res.json({ task });
});
module.exports = router;

// src/modules/members/routes.js
const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  try {
    const { userId, role } = req.body;
    if (!userId || typeof userId !== 'string' || userId.trim() === '') {
      return sendError(res, 400, 'INVALID_INPUT', 'UserId is required and must be a non-empty string');
    }
    if (!role || typeof role !== 'string' || role.trim() === '') {
      return sendError(res, 400, 'INVALID_INPUT', 'Role is required and must be a non-empty string');
    }
    const member = await membersService.addMember(req.params.projectId, userId, role);
    if (!member) return sendError(res, 409, 'MEMBER_DUPLICATE', 'Member already exists');
  res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');

let membersStore = [];

const addMember = (projectId, userId, role) => {
  const member = { id: randomUUID(), projectId, userId, role };
  membersStore.push(member);
  return Promise.resolve(member);
};

module.exports = { addMember };
const __botEvalMembersDupGuard = module.exports.addMember;
const __botEvalMembersDupStore = [];
module.exports.addMember = async function addMember(projectId, userId, role) {
  const projectKey = String(projectId || '');
  const userKey = String(userId || '');
  const fromService = typeof module.exports.getMembers === 'function' ? await module.exports.getMembers(projectKey) : [];
  const baseline = Array.isArray(fromService) ? fromService : __botEvalMembersDupStore.filter(member => member && String(member.projectId || '') === projectKey);
  const existing = baseline.find(member => member && String(member.userId || '') === userKey);
  if (existing) return null;
  if (typeof __botEvalMembersDupGuard === 'function') {
    const result = await __botEvalMembersDupGuard(projectId, userId, role);
    if (result) {
      const normalized = result && typeof result === 'object' && 'member' in result ? result.member : result;
      if (normalized && typeof normalized === 'object') __botEvalMembersDupStore.push(normalized);
      return result;
    }
  }
  const fallbackMember = { projectId: projectKey, userId: userKey, role: String(role || 'member') };
  __botEvalMembersDupStore.push(fallbackMember);
  return fallbackMember;
};

